def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent, complex sentence. Unknown predicates fall back to a generic phrasing.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    # Helper to build a clause fragment *without* repeating the subject.
    def _clause_body(p: str, o: str) -> str:
        if p == "cityServed":
            return f"serves the city of {o}"
        if p == "aircraftHelicopter":
            return f"operates the helicopter {o}"
        if p == "transportAircraft":
            return f"operates the transport aircraft {o}"
        if p == "aircraftFighter":
            return f"operates the fighter aircraft {o}"
        if p == "attackAircraft":
            return f"operates the attack aircraft {o}"
        if p == "battle":
            return f"participated in the battle {o}"
        if p == "location":
            return f"is located in {o}"
        if p == "country":
            return f"is in {o}"
        if p == "isPartOf":
            return f"is part of {o}"
        if p == "elevationAboveTheSeaLevel":
            return f"lies at an elevation of {o} metres above sea level"
        if p == "elevationAboveTheSeaLevelInFeet":
            return f"lies at an elevation of {o} feet above sea level"
        if p == "elevationAboveTheSeaLevelInMetres":
            return f"lies at an elevation of {o} metres above sea level"
        if p == "operatingOrganisation":
            return f"is operated by {o}"
        if p == "runwaySurfaceType":
            return f"has a runway surface of {o}"
        if p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0]
            ordinal = {"1st": "first", "2nd": "second", "3rd": "third", "4th": "fourth", "5th": "fifth"}.get(idx.lower(), idx.lower())
            return f"its {ordinal} runway is {o} feet long"
        if p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0]
            ordinal = {"1st": "first", "2nd": "second", "3rd": "third", "4th": "fourth", "5th": "fifth"}.get(idx.lower(), idx.lower())
            return f"its {ordinal} runway is {o} metres long"
        # (additional mappings would continue here)

    # Build clauses
    clauses: list[str] = [_clause(t.subject, t.predicate, _clean(t.object)) for t in triples]

    # Combine all clauses into one fluent sentence
    # Start with the first clause as the main statement
    sentence = clauses[0]
    for idx, cl in enumerate(clauses[1:], start=1):
        # Use "which" for the first added clause, then "and" for the rest
        connector = "which" if idx == 1 else "and"
        # lower‑case the first character of the added clause for smoother flow
        cl = cl[0].lower() + cl[1:] if cl else cl
        sentence += f", {connector} {cl}"
    sentence += "."

    # Capitalise first character
    return sentence[0].upper() + sentence[1:]

